import type { ChartUnit } from '../../core/types/chart-unit.js';
import { ColorToken } from '../../core/types/color-palette.js';
export interface Dimension extends Record<string, unknown> {
    id: string;
    name: string;
    value: number;
    cumulativeValue?: number;
    category?: string;
}
export interface ColoredDimension extends Dimension {
    color: ColorToken;
}
export interface CategoricalBarData {
    id: string;
    name: string;
    unit?: ChartUnit;
    dimensions: Dimension[];
}
export type ChartDimension = Omit<CategoricalBarData, 'unit' | 'dimensions' | 'id'>;
export interface ColoredChartDimension extends ChartDimension {
    color: ColorToken;
}
export interface DimensionXYPoint {
    x: number;
    y: number;
    datapoint: ColoredDimension;
}
export type CategoryMetadata = {
    id: string;
    name: string;
};
export type DimensionMetadata = {
    id: string;
    name: string;
    color: ColorToken;
    legendColor?: ColorToken;
    value: number;
    cumulativeValue?: number;
};
export type WeakMapCategory = WeakMap<object, CategoryMetadata>;
export type WeakMapDimension = WeakMap<object, DimensionMetadata>;
